    telemetry: {
        UTILITY_KW: 12,
        LOAD_KW: 30,
        PV_KW: 0
    },
    baseTelemetry: {
        soc: 0.62,
        gridStatus: "normal",
        realtimeActivePowerKwRequest: 0
    },
    schedule
});

