    input: msg.payload,
    selectedPlan: schedule.selectedPlan,
    strategy: schedule.strategy,
    constraints: schedule.constraints,
    command: cycle.command,
    writerEnvelopes: cycle.writerEnvelopes,
    pipeline: cycle.pipeline,
    diagnostics: cycle.diagnostics
};
msg.topic = "scheduler-unified-control-preview";
